mapper.select:
SELECT id, order_id, user_id, seckill_activity_id, product_id, price, quantity, status, payment_method, create_time, update_time
FROM seckill_order
WHERE order_id = #{orderId}

mapper.update:
UPDATE seckill_order
SET status = #{targetStatus},
    payment_method = #{paymentMethod},
    update_time = #{updateTime}
WHERE order_id = #{orderId}
  AND status = #{currentStatus}
